    val m = grid.size
    val n = grid[0].size
    val visited = Array(m){ Array(n){false} }
    var count = 0L

    fun dfs(i: Int, j: Int): Long {
        if (i < 0 || i >= m || j < 0 || j >= n || grid[i][j] == 0L || visited[i][j]) return 0L
        visited[i][j] = true
        var sum = grid[i][j]
        val directions = arrayOf(intArrayOf(0,1), intArrayOf(1,0), intArrayOf(0,-1), intArrayOf(-1,0))
        for (dir in directions) {
            sum += dfs(dir[0] + i, dir[1] + j)
        }
        return sum
    }

    for (i in 0 until m) {
        for (j in 0 until n) {
            if (grid[i][j] != 0L && !visited[i][j]) {
                val sum = dfs(i, j)
                if (sum % k == 0L) count++
            }
        }
    }

    return count
}
